     1→"use client";
     2→
     3→import { useRouter } from "next/navigation";
     4→
     5→import { useState, useEffect, useCallback } from "react";
     6→import { X, Archive, Trash2, Check, ArrowRight, AlertTriangle } from "lucide-react";
     7→import { cn } from "@/lib/utils";
     8→import { DecisionBadge } from "@/components/ui/decision-badge";
     9→import { AxisScoreBar } from "@/components/ui/axis-score-bar";
    10→
    11→interface Project {
    12→    id: string;
    13→    title?: string;
    14→    text: string;
    15→    description?: string;
    16→    color?: string;
    17→    globalScore?: number;
    18→    recommendation?: string;
    19→    confidenceLevel?: string;
    20→    viabilityScore?: number;
    21→    classification?: string;
    22→    timestamp: string;
    23→    isDemo?: boolean;
    24→    isArchived?: boolean;
    25→    analysis?: {
    26→        axes?: { label: string; score: number; justification?: string }[];
    27→        synthesis?: string;
    28→        risks?: string[];
    29→    };
    30→}
    31→
    32→interface ProjectDetailOverlayProps {
    33→    project: Project | null;
    34→    open: boolean;
    35→    onClose: () => void;
    36→    onSave: (id: string, updates: { title?: string; description?: string }) => void;
    37→    onArchive: (id: string) => void;
    38→    onUnarchive: (id: string) => void;
    39→    onDelete: (id: string) => void;
    40→}
    41→
    42→const DEMO_SYNTHESIS = "Ce projet presente un potentiel interessant. L'analyse des six axes revele des forces dans le business model et l'adequation fondateur-projet. Quelques points d'attention sur la differenciation et la faisabilite technique meritent une exploration plus approfondie avant de passer a l'etape suivante.";
    43→
    44→const DEMO_RISKS = [
    45→    "Complexite reglementaire potentielle dans le secteur cible",
    46→    "Cout de developpement initial eleve pour le MVP",
    47→    "Competition existante avec des acteurs bien etablis",
    48→    "Dependance a des facteurs externes non controlables",
    49→];
    50→
    51→function getDecision(p: Project): string {
    52→    return p.recommendation ?? p.classification ?? "DRAFT";
    53→}
    54→
    55→function generateDemoAxes(score: number): { label: string; score: number; justification?: string }[] {
    56→    const base = score / 10;
    57→    return [
    58→        { label: "Probleme", score: Math.min(10, Math.round(base * 1.1)) },
    59→        { label: "Marche", score: Math.min(10, Math.round(base * 0.95)) },
    60→        { label: "Differenciation", score: Math.min(10, Math.round(base * 1.2)) },
    61→        { label: "Faisabilite", score: Math.min(10, Math.round(base * 0.9)) },
    62→        { label: "Business Model", score: Math.min(10, Math.round(base * 1.05)) },
    63→        { label: "Founder Fit", score: Math.min(10, Math.round(base * 1.0)) },
    64→    ];
    65→}
    66→
    67→export function ProjectDetailOverlay({ project, open, onClose, onSave, onArchive, onUnarchive, onDelete }: ProjectDetailOverlayProps) {
    68→    const [editTitle, setEditTitle] = useState("");
    69→    const [editDescription, setEditDescription] = useState("");
    70→    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    71→    const router = useRouter();
    72→
    73→    const getSmartAction = (p: Project) => {
    74→        const decision = getDecision(p);
    75→
    76→        switch (decision) {
    77→            case 'GO':
    78→                return {
    79→                    label: "Ouvrir au Lab 2",
    80→                    action: () => router.push(`/workspace/laboratoire-2-structuration/${p.id}`),
    81→                    variant: 'primary',
    82→                    disabled: false,
    83→                    icon: ArrowRight
    84→                };
    85→            case 'EXPLORE':
    86→            case 'PARK':
    87→            case 'DRAFT':
    88→                return {
    89→                    label: "Ouvrir au Lab 1",
    90→                    action: () => router.push(`/workspace/laboratoire-1-discovery/${p.id}`),
    91→                    variant: 'primary',
    92→                    disabled: false,
    93→                    icon: ArrowRight
    94→                };
    95→            case 'KILL':
    96→                return {
    97→                    label: "Dossier Rejeté",
    98→                    action: null,
    99→                    disabled: true,
   100→                    variant: 'outline',
   101→                    icon: AlertTriangle
   102→                };
   103→            default:
   104→                return {
   105→                    label: "Ouvrir le dossier",
   106→                    action: () => router.push(`/workspace/laboratoire-1-discovery/${p.id}`),
   107→                    variant: 'primary',
   108→                    disabled: false,
   109→                    icon: ArrowRight
   110→                };
   111→        }
   112→    };
   113→
   114→    useEffect(() => {
   115→        if (project) {
   116→            setEditTitle(project.title || project.text || "");
   117→            setEditDescription(project.description || "");
   118→        }
   119→    }, [project]);
   120→
   121→    const handleEscape = useCallback((e: KeyboardEvent) => {
   122→        if (e.key === "Escape") onClose();
   123→    }, [onClose]);
   124→
   125→    useEffect(() => {
   126→        if (open) {
   127→            document.addEventListener("keydown", handleEscape);
   128→            document.body.style.overflow = "hidden";
   129→        }
   130→        return () => {
   131→            document.removeEventListener("keydown", handleEscape);
   132→            document.body.style.overflow = "";
   133→        };
   134→    }, [open, handleEscape]);
   135→
   136→    if (!open || !project) return null;
   137→
   138→    const score = project.globalScore ?? project.viabilityScore ?? 0;
   139→    const decision = getDecision(project);
   140→    const confidence = project.confidenceLevel ?? (score >= 80 ? "HIGH" : score >= 50 ? "MEDIUM" : "LOW");
   141→    const axes = project.analysis?.axes ?? generateDemoAxes(score);
   142→    const synthesis = project.analysis?.synthesis ?? DEMO_SYNTHESIS;
   143→    const risks = project.analysis?.risks ?? DEMO_RISKS;
   144→
   145→    return (
   146→        <div
   147→            className="fixed inset-0 z-[100] flex items-center justify-center p-8"
   148→            style={{ background: "rgba(15,16,20,0.70)", backdropFilter: "blur(12px) saturate(0.8)", WebkitBackdropFilter: "blur(12px) saturate(0.8)" }}
   149→            onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
   150→        >
   151→            <div
   152→                className="relative w-full max-w-[960px] max-h-[90vh] overflow-y-auto rounded-[var(--radius-2xl)]"
   153→                style={{
   154→                    background: "var(--color-bg-card)",
   155→                    borderTop: "1px solid rgba(255,255,255,0.10)",
   156→                    borderLeft: "1px solid rgba(255,255,255,0.06)",
   157→                    borderRight: "1px solid rgba(255,255,255,0.06)",
   158→                    borderBottom: "1px solid rgba(0,0,0,0.3)",
   159→                    scrollbarWidth: "thin",
   160→                    scrollbarColor: "var(--color-surface-1) transparent",
   161→                }}
   162→            >
   163→                {/* Close button */}
   164→                <button
   165→                    onClick={onClose}
   166→                    className="group absolute top-6 right-6 z-10 w-9 h-9 rounded-full bg-[rgba(255,255,255,0.03)] border border-transparent flex items-center justify-center text-[--color-text-muted] transition-all duration-300 hover:bg-[#0F1014] hover:border-[rgba(255,255,255,0.1)] hover:text-white hover:scale-110 active:scale-95"
   167→                >
   168→                    <X className="w-[18px] h-[18px] transition-transform duration-300 group-hover:rotate-90" />
   169→                </button>
   170→
   171→                {/* Main Content - Analysis Results Style */}
   172→                <div className="bg-[#2F323A] rounded-xl border-0 overflow-hidden ring-1 ring-white/5">
   173→                    <div className="grid md:grid-cols-[280px_1fr] h-full min-h-[500px]">
   174→
   175→                        {/* Sidebar: Score + Decision */}
   176→                        <div className="bg-[#22242B] p-8 flex flex-col items-center justify-center text-center gap-6 border-r border-[#3A3D45] relative">
   177→                            <div>
   178→                                <span className="text-gray-500 text-[10px] uppercase tracking-widest font-bold">
   179→                                    Score Global
   180→                                </span>
   181→                                <div className={cn(
   182→                                    "text-7xl font-sans font-bold tracking-tighter mt-2",
   183→                                    score >= 70 ? "text-white" : "text-gray-400"
   184→                                )}>
   185→                                    {score}
   186→                                </div>
   187→                                <div className="text-gray-500 text-sm mt-1">/100</div>
   188→                            </div>
   189→
   190→                            <DecisionBadge decision={decision} />
   191→
   192→                            <div className="text-[10px] text-gray-500 uppercase tracking-widest">
   193→                                Confiance: {confidence}
   194→                            </div>
   195→
   196→                            {/* Smart Action Button - Sidebar Position */}
   197→                            <div className="w-full pt-6 border-t border-[#3A3D45] mt-2 flex flex-col gap-3">
   198→                                {(() => {
   199→                                    const action = getSmartAction(project);
   200→                                    const Icon = action.icon || ArrowRight;
   201→                                    let reasoning = "";
   202→                                    let labDescription = "";
   203→
   204→                                    switch (getDecision(project)) {
   205→                                        case 'GO':
   206→                                            reasoning = `Score > 75 (${score}/100) : Potentiel confirmé.`;
   207→                                            labDescription = "Laboratoire de Structuration : Transformez l'idée en produit viable.";
   208→                                            break;
   209→                                        case 'EXPLORE':
   210→                                        case 'PARK':
   211→                                        case 'DRAFT':
   212→                                            reasoning = `Score intermédiaire (${score}/100) : Incertitudes détectées.`;
   213→                                            labDescription = "Laboratoire de Découverte : Analysez et levez les doutes.";
   214→                                            break;
   215→                                        case 'KILL':
   216→                                            reasoning = `Score critique (${score}/100) : Risques bloquants identifiés.`;
   217→                                            labDescription = "Le projet ne répond pas aux criterios minimaux.";
   218→                                            break;
   219→                                    }
   220→
   221→                                    return (
   222→                                        <>
   223→                                            <div className="text-xs text-center space-y-1">
   224→                                                <p className="text-gray-400 font-medium">{reasoning}</p>
   225→                                                <p className="text-[10px] text-gray-500 leading-tight">{labDescription}</p>
   226→                                            </div>
   227→
   228→                                            <button
   229→                                                onClick={() => {
   230→                                                    if (action.action) {
   231→                                                        action.action();
   232→                                                        onClose();
   233→                                                    }
   234→                                                }}
   235→                                                disabled={action.disabled}
   236→                                                className={cn(
   237→                                                    "w-full flex items-center justify-center gap-2 px-4 py-3 rounded-[var(--radius-md)] text-sm font-semibold transition-all duration-200",
   238→                                                    action.disabled
   239→                                                        ? "bg-[#2A2D35] text-[--color-text-muted] cursor-not-allowed border border-[#3A3D45]"
   240→                                                        : "bg-[#FF6B35] text-white hover:bg-[#F78E21] hover:scale-[1.02] shadow-lg shadow-[#FF6B35]/20"
   241→                                                )}
   242→                                            >
   243→                                                {action.label}
   244→                                                <Icon className="w-4 h-4" />
   245→                                            </button>
   246→                                        </>
   247→                                    );
   248→                                })()}
   249→                            </div>
   250→                        </div>
   251→
   252→                        {/* Main Content */}
   253→                        <div className="p-8 flex flex-col bg-[#2F323A]">
   254→                            <div className="flex-1 space-y-8">
   255→                                {/* Dossier Header */}
   256→                                <div className="mb-6">
   257→                                    <div className="text-[10px] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-2">DOSSIER</div>
   258→                                    <h2 className="text-2xl font-semibold text-white mb-3">{project.title || project.text}</h2>
   259→                                    <p className="text-sm text-[--color-text-secondary] leading-relaxed">
   260→                                        {project.description || "Aucune description disponible."}
   261→                                    </p>
   262→                                </div>
   263→
   264→                                {/* Verdict d'Analyse */}
   265→                                <div>
   266→                                    <h3 className="text-lg font-medium text-white mb-3 flex items-center gap-2">
   267→                                        <ArrowRight className="w-4 h-4 text-[#F75105]" />
   268→                                        Verdict d'Analyse
   269→                                    </h3>
   270→                                    <p className="text-gray-300 text-sm leading-relaxed pl-6 border-l-2 border-[#3A3D45]">
   271→                                        &ldquo;{synthesis}&rdquo;
   272→                                    </p>
   273→                                </div>
   274→
   275→                                {/* Détail par Axe */}
   276→                                <div className="space-y-3">
   277→                                    <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4">
   278→                                        Détail par Axe
   279→                                    </h4>
   280→                                    {axes.map((axis) => (
   281→                                        <div key={axis.label} className="p-4 rounded-lg bg-[#22242B]/50 border border-white/5 hover:border-[#F75105]/30 transition-colors group">
   282→                                            <details className="group/details">
   283→                                                <summary className="list-none cursor-pointer [&::-webkit-details-marker]:hidden outline-none">
   284→                                                    <AxisScoreBar
   285→                                                        label={axis.label}
   286→                                                        score={axis.score * 10}
   287→                                                        blockingGap={false}
   288→                                                    />
   289→                                                </summary>
   290→                                                <div className="pt-3 pl-[140px] text-xs text-gray-400 leading-relaxed animate-in fade-in slide-in-from-top-1 duration-200 border-t border-white/5 mt-3">
   291→                                                    <p>{axis.justification || "Détail de l'analyse non disponible pour cet axe."}</p>
   292→                                                </div>
   293→                                            </details>
   294→                                        </div>
   295→                                    ))}
   296→                                </div>
   297→
   298→                                {/* Risques Identifiés */}
   299→                                {risks.length > 0 && (
   300→                                    <div>
   301→                                        <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
   302→                                            <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
   303→                                            Risques Identifiés
   304→                                        </h4>
   305→                                        <ul className="list-none space-y-2">
   306→                                            {risks.map((risk, i) => (
   307→                                                <li key={i} className="flex items-start gap-3 text-sm text-[--color-text-secondary] leading-relaxed">
   308→                                                    <div className="w-1.5 h-1.5 rounded-full bg-[--color-brand-primary] mt-[7px] shrink-0" />
   309→                                                    <span>{risk}</span>
   310→                                                </li>
   311→                                            ))}
   312→                                        </ul>
   313→                                    </div>
   314→                                )}
   315→
   316→                                {/* Editable Parameters */}
   317→                                <div>
   318→                                    <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4">
   319→                                        Paramètres du Dossier
   320→                                    </h4>
   321→                                    <div className="flex flex-col gap-4">
   322→                                        <div className="flex flex-col gap-2">
   323→                                            <label className="text-xs font-bold uppercase tracking-[0.1em] text-white">
   324→                                                Nom du Dossier
   325→                                            </label>
   326→                                            <input
   327→                                                type="text"
   328→                                                value={editTitle}
   329→                                                onChange={(e) => setEditTitle(e.target.value)}
   330→                                                placeholder="Renommer le dossier..."
   331→                                                className="bg-[#22242B] border border-[--color-border-default] rounded-[var(--radius-md)] px-4 py-3 text-[15px] font-medium text-[--color-text-primary] outline-none transition-all duration-200 placeholder:text-[--color-text-muted] placeholder:font-normal focus:border-[#F75105] focus:border-[1px]"
   332→                                            />
   333→                                        </div>
   334→                                        <div className="flex flex-col gap-2">
   335→                                            <label className="text-xs font-bold uppercase tracking-[0.1em] text-white">
   336→                                                Description
   337→                                            </label>
   338→                                            <textarea
   339→                                                value={editDescription}
   340→                                                onChange={(e) => setEditDescription(e.target.value)}
   341→                                                placeholder="Ajouter une description..."
   342→                                                rows={3}
   343→                                                className="bg-[#22242B] border border-[--color-border-default] rounded-[var(--radius-md)] px-4 py-3 text-[15px] font-medium text-[--color-text-primary] outline-none transition-all duration-200 placeholder:text-[--color-text-muted] placeholder:font-normal resize-none focus:border-[#F75105] focus:border-[1px]"
   344→                                            />
   345→                                        </div>
   346→                                    </div>
   347→                                </div>
   348→                            </div>
   349→
   350→                            {/* Actions row */}
   351→                            <div className="flex items-center gap-3 pt-4 border-t border-[#3A3D45] mt-8">
   352→                                <button
   353→                                    onClick={() => {
   354→                                        onSave(project.id, { title: editTitle, description: editDescription });
   355→                                    }}
   356→                                    className="group inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border border-transparent bg-transparent text-[--color-text-muted] transition-all duration-200 hover:bg-[rgba(74,222,128,0.1)] hover:border-[rgba(74,222,128,0.3)] hover:border hover:text-green-400"
   357→                                >
   358→                                    <Check className="w-4 h-4 transition-colors group-hover:text-green-400" />
   359→                                    Sauvegarder
   360→                                </button>
   361→                                {project.isArchived ? (
   362→                                    <button
   363→                                        onClick={() => onUnarchive(project.id)}
   364→                                        className="group inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border border-transparent bg-transparent text-[--color-text-muted] transition-all duration-200 hover:bg-[#22242B] hover:text-white hover:border-[#3A3D45] hover:border"
   365→                                    >
   366→                                        <Archive className="w-4 h-4 transition-colors group-hover:text-white" />
   367→                                        Désarchiver
   368→                                    </button>
   369→                                ) : (
   370→                                    <button
   371→                                        onClick={() => onArchive(project.id)}
   372→                                        className="group inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border border-transparent bg-transparent text-[--color-text-muted] transition-all duration-200 hover:bg-[#22242B] hover:text-white hover:border-[#3A3D45] hover:border"
   373→                                    >
   374→                                        <Archive className="w-4 h-4 transition-colors group-hover:text-white" />
   375→                                        Archiver
   376→                                    </button>
   377→                                )}
   378→                                <button
   379→                                    onClick={() => setShowDeleteConfirm(true)}
   380→                                    className="group inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border border-transparent bg-transparent text-[--color-text-muted] transition-all duration-200 hover:bg-[rgba(239,68,68,0.1)] hover:border-[rgba(239,68,68,0.3)] hover:border hover:text-red-400"
   381→                                >
   382→                                    <Trash2 className="w-4 h-4 transition-colors duration-200 group-hover:text-red-400" />
   383→                                    Supprimer
   384→                                </button>
   385→                                <div className="flex-1" />
   386→
   387→                            </div>
   388→                        </div>
   389→                    </div>
   390→
   391→                    {/* Delete Confirmation Modal */}
   392→                    {showDeleteConfirm && (
   393→                        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 animate-in fade-in duration-200">
   394→                            <div className="bg-[--color-bg-card] border border-[--color-border-default] rounded-[var(--radius-2xl)] p-8 max-w-md w-full mx-4 animate-in zoom-in-95 duration-200">
   395→                                <div className="flex items-start gap-4 mb-6">
   396→                                    <div className="w-12 h-12 rounded-full bg-[rgba(239,68,68,0.1)] border border-[rgba(239,68,68,0.2)] flex items-center justify-center shrink-0">
   397→                                        <Trash2 className="w-5 h-5 text-[--color-kill]" />
   398→                                    </div>
   399→                                    <div className="flex-1">
   400→                                        <h3 className="text-lg font-semibold text-white mb-2">Supprimer le dossier</h3>
   401→                                        <p className="text-sm text-[--color-text-secondary] leading-relaxed">
   402→                                            Êtes-vous sûr de vouloir supprimer définitivement ce dossier ? Cette action est irréversible.
   403→                                        </p>
   404→                                    </div>
   405→                                </div>
   406→                                <div className="flex items-center gap-3 justify-end">
   407→                                    <button
   408→                                        onClick={() => setShowDeleteConfirm(false)}
   409→                                        className="px-5 py-2.5 bg-transparent text-[--color-text-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-200 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong]"
   410→                                    >
   411→                                        Annuler
   412→                                    </button>
   413→                                    <button
   414→                                        onClick={() => {
   415→                                            onDelete(project.id);
   416→                                            setShowDeleteConfirm(false);
   417→                                        }}
   418→                                        className="px-5 py-2.5 bg-[--color-kill] text-white rounded-[var(--radius-md)] text-sm font-semibold transition-all duration-200 hover:bg-[#DC2626] hover:scale-[1.02]"
   419→                                    >
   420→                                        Supprimer définitivement
   421→                                    </button>
   422→                                </div>
   423→                            </div>
   424→                        </div>
   425→                    )}
   426→                </div>
   427→            </div>
   428→        </div >
   429→    );
   430→}
