"use client";

import { useRouter } from "next/navigation";

import { useState, useEffect, useCallback } from "react";
import { X, Archive, Trash2, Check, ArrowRight, AlertTriangle } from "lucide-react";
import { cn } from "@/lib/utils";
import { DecisionBadge } from "@/components/ui/decision-badge";
import { AxisScoreBar } from "@/components/ui/axis-score-bar";

interface Project {
    id: string;
    title?: string;
    text: string;
    description?: string;
    color?: string;
    globalScore?: number;
    recommendation?: string;
    confidenceLevel?: string;
    viabilityScore?: number;
    classification?: string;
    timestamp: string;
    isDemo?: boolean;
    isArchived?: boolean;
    analysis?: {
        axes?: { label: string; score: number; justification?: string }[];
        synthesis?: string;
        risks?: string[];
    };
}

interface ProjectDetailOverlayProps {
    project: Project | null;
    open: boolean;
    onClose: () => void;
    onSave: (id: string, updates: { title?: string; description?: string }) => void;
    onArchive: (id: string) => void;
    onUnarchive: (id: string) => void;
    onDelete: (id: string) => void;
}

const DEMO_SYNTHESIS = "Ce projet presente un potentiel interessant. L'analyse des six axes revele des forces dans le business model et l'adequation fondateur-projet. Quelques points d'attention sur la differenciation et la faisabilite technique meritent une exploration plus approfondie avant de passer a l'etape suivante.";

const DEMO_RISKS = [
    "Complexite reglementaire potentielle dans le secteur cible",
    "Cout de developpement initial eleve pour le MVP",
    "Competition existante avec des acteurs bien etablis",
    "Dependance a des facteurs externes non controlables",
];

function getDecision(p: Project): string {
    return p.recommendation ?? p.classification ?? "DRAFT";
}

function generateDemoAxes(score: number): { label: string; score: number; justification?: string }[] {
    const base = score / 10;
    return [
        { label: "Probleme", score: Math.min(10, Math.round(base * 1.1)) },
        { label: "Marche", score: Math.min(10, Math.round(base * 0.95)) },
        { label: "Differenciation", score: Math.min(10, Math.round(base * 1.2)) },
        { label: "Faisabilite", score: Math.min(10, Math.round(base * 0.9)) },
        { label: "Business Model", score: Math.min(10, Math.round(base * 1.05)) },
        { label: "Founder Fit", score: Math.min(10, Math.round(base * 1.0)) },
    ];
}

export function ProjectDetailOverlay({ project, open, onClose, onSave, onArchive, onUnarchive, onDelete }: ProjectDetailOverlayProps) {
    const [editTitle, setEditTitle] = useState("");
    const [editDescription, setEditDescription] = useState("");
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const router = useRouter();

    const getSmartAction = (p: Project) => {
        const decision = getDecision(p);

        switch (decision) {
            case 'GO':
                return {
                    label: "Ouvrir au Lab 2",
                    action: () => router.push(`/workspace/laboratoire-2-structuration/${p.id}`),
                    variant: 'primary',
                    disabled: false,
                    icon: ArrowRight
                };
            case 'EXPLORE':
            case 'PARK':
            case 'DRAFT':
                return {
                    label: "Ouvrir au Lab 1",
                    action: () => router.push(`/workspace/laboratoire-1-discovery/${p.id}`),
                    variant: 'primary',
                    disabled: false,
                    icon: ArrowRight
                };
            case 'KILL':
                return {
                    label: "Dossier Rejeté",
                    action: null,
                    disabled: true,
                    variant: 'outline',
                    icon: AlertTriangle
                };
            default:
                return {
                    label: "Ouvrir le dossier",
                    action: () => router.push(`/workspace/laboratoire-1-discovery/${p.id}`),
                    variant: 'primary',
                    disabled: false,
                    icon: ArrowRight
                };
        }
    };

    useEffect(() => {
        if (project) {
            setEditTitle(project.title || project.text || "");
            setEditDescription(project.description || "");
        }
    }, [project]);

    const handleEscape = useCallback((e: KeyboardEvent) => {
        if (e.key === "Escape") onClose();
    }, [onClose]);

    useEffect(() => {
        if (open) {
            document.addEventListener("keydown", handleEscape);
            document.body.style.overflow = "hidden";
        }
        return () => {
            document.removeEventListener("keydown", handleEscape);
            document.body.style.overflow = "";
        };
    }, [open, handleEscape]);

    if (!open || !project) return null;

    const score = project.globalScore ?? project.viabilityScore ?? 0;
    const decision = getDecision(project);
    const confidence = project.confidenceLevel ?? (score >= 80 ? "HIGH" : score >= 50 ? "MEDIUM" : "LOW");
    const axes = project.analysis?.axes ?? generateDemoAxes(score);
    const synthesis = project.analysis?.synthesis ?? DEMO_SYNTHESIS;
    const risks = project.analysis?.risks ?? DEMO_RISKS;

    return (
        <div
            className="fixed inset-0 z-[100] flex items-center justify-center p-8"
            style={{ background: "rgba(15,16,20,0.70)", backdropFilter: "blur(12px) saturate(0.8)", WebkitBackdropFilter: "blur(12px) saturate(0.8)" }}
            onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}
        >
            <div
                className="relative w-full max-w-[960px] max-h-[90vh] overflow-y-auto rounded-[var(--radius-2xl)]"
                style={{
                    background: "var(--color-bg-card)",
                    borderTop: "1px solid rgba(255,255,255,0.10)",
                    borderLeft: "1px solid rgba(255,255,255,0.06)",
                    borderRight: "1px solid rgba(255,255,255,0.06)",
                    borderBottom: "1px solid rgba(0,0,0,0.3)",
                    scrollbarWidth: "thin",
                    scrollbarColor: "var(--color-surface-1) transparent",
                }}
            >
                {/* Close button */}
                <button
                    onClick={onClose}
                    className="group absolute top-6 right-6 z-10 w-9 h-9 rounded-full bg-[rgba(255,255,255,0.03)] border border-transparent flex items-center justify-center text-[--color-text-muted] transition-all duration-300 hover:bg-[#0F1014] hover:border-[rgba(255,255,255,0.1)] hover:text-white hover:scale-110 active:scale-95"
                >
                    <X className="w-[18px] h-[18px] transition-transform duration-300 group-hover:rotate-90" />
                </button>

                {/* Main Content - Analysis Results Style */}
                <div className="bg-[#2F323A] rounded-xl border-0 overflow-hidden ring-1 ring-white/5">
                    <div className="grid md:grid-cols-[280px_1fr] h-full min-h-[500px]">

                        {/* Sidebar: Score + Decision */}
                        <div className="bg-[#22242B] p-8 flex flex-col items-center justify-center text-center gap-6 border-r border-[#3A3D45] relative">
                            <div>
                                <span className="text-gray-500 text-[10px] uppercase tracking-widest font-bold">
                                    Score Global
                                </span>
                                <div className={cn(
                                    "text-7xl font-sans font-bold tracking-tighter mt-2",
                                    score >= 70 ? "text-white" : "text-gray-400"
                                )}>
                                    {score}
                                </div>
                                <div className="text-gray-500 text-sm mt-1">/100</div>
                            </div>

                            <DecisionBadge decision={decision} />

                            <div className="text-[10px] text-gray-500 uppercase tracking-widest">
                                Confiance: {confidence}
                            </div>

                            {/* Smart Action Button - Sidebar Position */}
                            <div className="w-full pt-6 border-t border-[#3A3D45] mt-2 flex flex-col gap-3">
                                {(() => {
                                    const action = getSmartAction(project);
                                    const Icon = action.icon || ArrowRight;
                                    let reasoning = "";
                                    let labDescription = "";

                                    switch (getDecision(project)) {
                                        case 'GO':
                                            reasoning = `Score > 75 (${score}/100) : Potentiel confirmé.`;
                                            labDescription = "Laboratoire de Structuration : Transformez l'idée en produit viable.";
                                            break;
                                        case 'EXPLORE':
                                        case 'PARK':
                                        case 'DRAFT':
                                            reasoning = `Score intermédiaire (${score}/100) : Incertitudes détectées.`;
                                            labDescription = "Laboratoire de Découverte : Analysez et levez les doutes.";
                                            break;
                                        case 'KILL':
                                            reasoning = `Score critique (${score}/100) : Risques bloquants identifiés.`;
                                            labDescription = "Le projet ne répond pas aux criterios minimaux.";
                                            break;
                                    }

                                    return (
                                        <>
                                            <div className="text-xs text-center space-y-1">
                                                <p className="text-gray-400 font-medium">{reasoning}</p>
                                                <p className="text-[10px] text-gray-500 leading-tight">{labDescription}</p>
                                            </div>

                                            <button
                                                onClick={() => {
                                                    if (action.action) {
                                                        action.action();
                                                        onClose();
                                                    }
                                                }}
                                                disabled={action.disabled}
                                                className={cn(
