                                    </p>
                                </div>

                                {/* Détail par Axe */}
                                <div className="space-y-3">
                                    <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4">
                                        Détail par Axe
                                    </h4>
                                    {axes.map((axis) => (
                                        <div key={axis.label} className="p-4 rounded-lg bg-[#22242B]/50 border border-white/5 hover:border-[#F75105]/30 transition-colors group">
                                            <details className="group/details">
                                                <summary className="list-none cursor-pointer [&::-webkit-details-marker]:hidden outline-none">
                                                    <AxisScoreBar
                                                        label={axis.label}
                                                        score={axis.score * 10}
                                                        blockingGap={false}
                                                    />
                                                </summary>
                                                <div className="pt-3 pl-[140px] text-xs text-gray-400 leading-relaxed animate-in fade-in slide-in-from-top-1 duration-200 border-t border-white/5 mt-3">
                                                    <p>{axis.justification || "Détail de l'analyse non disponible pour cet axe."}</p>
                                                </div>
                                            </details>
                                        </div>
                                    ))}
                                </div>

                                {/* Risques Identifiés */}
                                {risks.length > 0 && (
                                    <div>
                                        <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
                                            <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
