                                    >
                                        <Archive className="w-4 h-4 transition-colors group-hover:text-white" />
                                        Désarchiver
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => onArchive(project.id)}
                                        className="group inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border border-transparent bg-transparent text-[--color-text-muted] transition-all duration-200 hover:bg-[#22242B] hover:text-white hover:border-[#3A3D45] hover:border"
                                    >
                                        <Archive className="w-4 h-4 transition-colors group-hover:text-white" />
                                        Archiver
                                    </button>
                                )}
                                <button
                                    onClick={() => setShowDeleteConfirm(true)}
                                    className="group inline-flex items-center gap-2 px-4 py-2.5 rounded-lg border border-transparent bg-transparent text-[--color-text-muted] transition-all duration-200 hover:bg-[rgba(239,68,68,0.1)] hover:border-[rgba(239,68,68,0.3)] hover:border hover:text-red-400"
                                >
                                    <Trash2 className="w-4 h-4 transition-colors duration-200 group-hover:text-red-400" />
                                    Supprimer
                                </button>
                                <div className="flex-1" />

                            </div>
                        </div>
                    </div>

                    {/* Delete Confirmation Modal */}
                    {showDeleteConfirm && (
                        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 animate-in fade-in duration-200">
                            <div className="bg-[--color-bg-card] border border-[--color-border-default] rounded-[var(--radius-2xl)] p-8 max-w-md w-full mx-4 animate-in zoom-in-95 duration-200">
                                <div className="flex items-start gap-4 mb-6">
                                    <div className="w-12 h-12 rounded-full bg-[rgba(239,68,68,0.1)] border border-[rgba(239,68,68,0.2)] flex items-center justify-center shrink-0">
                                        <Trash2 className="w-5 h-5 text-[--color-kill]" />
                                    </div>
                                    <div className="flex-1">
                                        <h3 className="text-lg font-semibold text-white mb-2">Supprimer le dossier</h3>
                                        <p className="text-sm text-[--color-text-secondary] leading-relaxed">
                                            Êtes-vous sûr de vouloir supprimer définitivement ce dossier ? Cette action est irréversible.
                                        </p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3 justify-end">
                                    <button
                                        onClick={() => setShowDeleteConfirm(false)}
                                        className="px-5 py-2.5 bg-transparent text-[--color-text-secondary] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-200 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong]"
                                    >
                                        Annuler
                                    </button>
                                    <button
                                        onClick={() => {
                                            onDelete(project.id);
                                            setShowDeleteConfirm(false);
                                        }}
                                        className="px-5 py-2.5 bg-[--color-kill] text-white rounded-[var(--radius-md)] text-sm font-semibold transition-all duration-200 hover:bg-[#DC2626] hover:scale-[1.02]"
                                    >
                                        Supprimer définitivement
                                    </button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div >
    );
}

