                        <p className="text-base text-[--color-text-muted] flex items-center gap-2">
                            <strong className="text-[--color-text-secondary] font-medium">{projects.filter(p => !p.isArchived).length}</strong> dossier{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""} actif{projects.filter(p => !p.isArchived).length !== 1 ? "s" : ""}
                            {" "}&middot;{" "}
                            <strong className="text-[--color-text-secondary] font-medium">{goCount}</strong> projet{goCount !== 1 ? "s" : ""} valide{goCount !== 1 ? "s" : ""} GO
                            {" "}&middot;{" "}
                            <strong className="text-[--color-text-secondary] font-medium">{attentionCount}</strong> necessite{attentionCount !== 1 ? "nt" : ""} votre attention
                        </p>
                        <button
                            onClick={() => setShowArchived(!showArchived)}
                            className="group inline-flex items-center gap-2 px-4 py-2 bg-transparent text-[--color-text-muted] border border-[--color-border-default] rounded-[var(--radius-md)] text-sm font-medium transition-all duration-300 hover:text-white hover:bg-[rgba(255,255,255,0.06)] hover:border-[--color-border-strong] hover:scale-[1.02] active:scale-[0.98]"
                        >
                            <Archive className="w-4 h-4 transition-transform duration-300 group-hover:scale-110" />
                            {showArchived ? "Dossiers actifs" : "Dossiers archivés disponibles"}
                        </button>
                    </div>
                </div>

                {/* Grid */}
                <div className={cn(
                    "animate-in fade-in zoom-in-95 duration-500",
