    69→const submitRequestSchema = z.object({
    70→  action: z.literal('submit'),
    71→  enrichment_id: z.string().min(1),
    72→  idea_id: z.string().min(1),
    73→  analysis: z.object({
    74→    problem: axisAnalysisSchema,
    75→    market: axisAnalysisSchema,
    76→    differentiation: axisAnalysisSchema,
    77→    feasibility: axisAnalysisSchema,
    78→    business: axisAnalysisSchema,
    79→    founder_fit: axisAnalysisSchema,
    80→  }),
    81→  scores: z.object({
    82→    global_score: z.number().int().min(0).max(100),
    83→  }),
    84→  decision: z.object({
    85→    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
    86→  }),
    87→  questions: z.array(z.object({
    88→    question_id: z.string(),
    89→    axis: z.enum(['problem', 'market', 'differentiation', 'feasibility', 'business', 'founder_fit']),
    90→    options: z.array(z.object({
    91→      id: z.string(),
    92→      score_adjustment: z.number(),
    93→    })),
    94→  })),
    95→  responses: z.array(enrichmentResponseSchema),
    96→});
    97→
    98→// ═══════════════════════════════════════════════════════════════════
    99→// POST /api/enrichment
   100→// ═══════════════════════════════════════════════════════════════════
   101→
   102→export async function POST(req: Request) {
   103→  try {
   104→    let body: unknown;
   105→    try {
   106→      body = await req.json();
   107→    } catch {
   108→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Request body is not valid JSON');
   109→    }
   110→
   111→    // Determine action
   112→    const actionCheck = z.object({ action: z.enum(['generate', 'submit']) }).safeParse(body);
   113→    if (!actionCheck.success) {
   114→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Missing or invalid "action" field. Must be "generate" or "submit".');
   115→    }
   116→
   117→    if (actionCheck.data.action === 'generate') {
   118→      return handleGenerate(body);
   119→    } else {
   120→      return handleSubmit(body);
   121→    }
   122→  } catch (error: unknown) {
   123→    const err = error as Error;
   124→    console.error('Unexpected enrichment error:', err);
   125→    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
   126→  }
   127→}
   128→
   129→// ═══════════════════════════════════════════════════════════════════
   130→// MODE 1 : GENERATE QUESTIONS
   131→// ═══════════════════════════════════════════════════════════════════
   132→
   133→async function handleGenerate(body: unknown) {
   134→  const validation = generateRequestSchema.safeParse(body);
   135→  if (!validation.success) {
   136→    return errorResponse(400, 'INPUT_SCHEMA_INVALID', validation.error.issues.map((i) => `${i.path.join('.')} ${i.message}`).join('; '));
   137→  }
   138→
   139→  const data = validation.data;
   140→  const analysis = data.analysis as AnalysisAxes;
   141→
   142→  // ─── Check enrichment is actually needed ──────────────────────
   143→  const enrichment = computeEnrichmentDecision(
   144→    analysis,
   145→    data.scores.global_score,
   146→    data.decision.confidence_level
   147→  );
   148→
   149→  if (!enrichment.required) {
   150→    return NextResponse.json({
   151→      enrichment_id: null,
   152→      required: false,
   153→      message: 'No enrichment triggers detected',
   154→      trigger_axes: [],
   155→      questions: [],
   156→    });
   157→  }
   158→
   159→  // ─── Build enrichment prompt ──────────────────────────────────
   160→  const triggers = detectEnrichmentTriggers(
   161→    analysis,
   162→    data.scores.global_score,
   163→    data.decision.confidence_level
   164→  );
   165→  const prioritized = prioritizeAxes(analysis, triggers);
   166→
   167→  const axesInfo = prioritized.map((p) => ({
   168→    axis: p.axis,
   169→    score: p.score,
   170→    justification: analysis[p.axis].justification,
   171→  }));
   172→
   173→  const enrichmentPrompt = buildEnrichmentPrompt(
   174→    axesInfo,
   175→    data.idea_summary,
   176→    enrichment.max_questions
   177→  );
   178→
   179→  // ─── Call Claude API to generate questions ────────────────────
   180→  let questionsJson: string;
   181→  try {
   182→    const message = await anthropic.messages.create({
   183→      model: AI_MODEL,
   184→      max_tokens: 2048,
   185→      temperature: 0.3,
   186→      system: assembleSystemPrompt(),
   187→      messages: [{ role: 'user', content: enrichmentPrompt }],
   188→    });
   189→
   190→    const textBlock = message.content.find((b) => b.type === 'text');
   191→    if (!textBlock || textBlock.type !== 'text') {
   192→      return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'LLM returned no text content');
   193→    }
   194→    questionsJson = textBlock.text;
   195→  } catch (error: unknown) {
   196→    const err = error as Error;
   197→    console.error('Claude API error (enrichment):', err);
   198→    return errorResponse(500, 'AI_CALL_FAILED', `Claude API error: ${err.message}`);
   199→  }
   200→
   201→  // ─── Parse and validate questions ─────────────────────────────
   202→  let parsedQuestions: unknown;
   203→  try {
   204→    let jsonStr = questionsJson.trim();
   205→    if (jsonStr.startsWith('```json')) jsonStr = jsonStr.slice(7);
   206→    else if (jsonStr.startsWith('```')) jsonStr = jsonStr.slice(3);
   207→    if (jsonStr.endsWith('```')) jsonStr = jsonStr.slice(0, -3);
   208→    parsedQuestions = JSON.parse(jsonStr.trim());
   209→  } catch {
   210→    console.error('Enrichment JSON parse error:', questionsJson.substring(0, 500));
   211→    return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'LLM output is not valid JSON');
   212→  }
   213→
   214→  // Validate each question
   215→  if (!Array.isArray(parsedQuestions)) {
   216→    return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'LLM output is not a JSON array');
   217→  }
   218→
   219→  const validatedQuestions: EnrichmentQuestion[] = [];
   220→  for (const q of parsedQuestions) {
   221→    const qValidation = enrichmentQuestionSchema.safeParse(q);
   222→    if (qValidation.success) {
   223→      validatedQuestions.push(qValidation.data as EnrichmentQuestion);
   224→    } else {
   225→      console.warn('Invalid question skipped:', qValidation.error.issues);
   226→    }
   227→  }
   228→
   229→  if (validatedQuestions.length === 0) {
   230→    return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'No valid questions generated by LLM');
   231→  }
   232→
   233→  const enrichmentId = crypto.randomUUID();
   234→
   235→  return NextResponse.json({
   236→    enrichment_id: enrichmentId,
   237→    idea_id: data.idea_id,
   238→    required: true,
   239→    timestamp: new Date().toISOString(),
   240→    trigger_axes: enrichment.trigger_axes,
   241→    questions: validatedQuestions,
   242→    max_questions: enrichment.max_questions,
   243→  });
   244→}
   245→
   246→// ═══════════════════════════════════════════════════════════════════
   247→// MODE 2 : SUBMIT RESPONSES & RECALCULATE
   248→// ═══════════════════════════════════════════════════════════════════
   249→
   250→async function handleSubmit(body: unknown) {
   251→  const validation = submitRequestSchema.safeParse(body);
   252→  if (!validation.success) {
   253→    return errorResponse(400, 'INPUT_SCHEMA_INVALID', validation.error.issues.map((i) => `${i.path.join('.')} ${i.message}`).join('; '));
   254→  }
   255→
   256→  const data = validation.data;
   257→  const analysis = data.analysis as AnalysisAxes;
   258→
   259→  // ─── Calculate adjustments from responses ─────────────────────
   260→  const adjustments: ScoreAdjustment[] = [];
   261→
   262→  for (const response of data.responses) {
   263→    if (response.status !== 'completed' || !response.selected_option_ids) {
   264→      continue; // skipped or timeout → no adjustment
   265→    }
   266→
   267→    // Find the corresponding question
   268→    const question = data.questions.find((q) => q.question_id === response.question_id);
   269→    if (!question) continue;
   270→
   271→    // Sum adjustments for selected options
   272→    let totalAdjustment = 0;
   273→    for (const optionId of response.selected_option_ids) {
   274→      const option = question.options.find((o) => o.id === optionId);
   275→      if (option) {
   276→        totalAdjustment += option.score_adjustment;
   277→      }
   278→    }
   279→
   280→    adjustments.push({
   281→      axis: question.axis as AnalysisAxis,
   282→      question_id: response.question_id,
   283→      adjustment: totalAdjustment,
   284→    });
   285→  }
   286→
   287→  // ─── Apply adjustments ────────────────────────────────────────
   288→  const { updatedAnalysis, newGlobalScore, enrichedAxes } =
   289→    applyEnrichmentAdjustments(analysis, adjustments);
   290→
   291→  // ─── Update confidence level ──────────────────────────────────
   292→  const newConfidence = updateConfidenceLevel(
   293→    data.decision.confidence_level,
   294→    enrichedAxes,
   295→    updatedAnalysis
   296→  );
   297→
   298→  // ─── Re-determine decision ────────────────────────────────────
   299→  const newDecision = determineDecision(newGlobalScore, updatedAnalysis, newConfidence);
   300→
   301→  // ─── Build scores maps ────────────────────────────────────────
   302→  const scoresBefore: Record<string, number> = {};
   303→  const scoresAfter: Record<string, number> = {};
   304→  for (const [axis, value] of Object.entries(analysis)) {
   305→    scoresBefore[axis] = value.score;
   306→  }
   307→  scoresBefore['global'] = data.scores.global_score;
   308→  for (const [axis, value] of Object.entries(updatedAnalysis)) {
   309→    scoresAfter[axis] = value.score;
   310→  }
   311→  scoresAfter['global'] = newGlobalScore;
   312→
   313→  return NextResponse.json({
   314→    enrichment_id: data.enrichment_id,
   315→    idea_id: data.idea_id,
   316→    timestamp: new Date().toISOString(),
   317→    scores_before: scoresBefore,
   318→    scores_after: scoresAfter,
   319→    decision_before: data.decision,
   320→    decision_after: {
   321→      recommendation: newDecision.recommendation,
   322→      confidence_level: newConfidence,
   323→      reasons: newDecision.reasons,
   324→    },
   325→    adjustments,
   326→    updated_analysis: updatedAnalysis,
   327→    updated_scores: {
   328→      global_score: newGlobalScore,
   329→      weights: CANONICAL_WEIGHTS,
   330→    },
   331→  });
   332→}
   333→
   334→// ═══════════════════════════════════════════════════════════════════
   335→// ERROR HELPER
   336→// ═══════════════════════════════════════════════════════════════════
   337→
   338→function errorResponse(status: number, code: string, message: string): NextResponse<ApiError> {
   339→  return NextResponse.json(
   340→    {
   341→      error: {
   342→        code,
   343→        message,
   344→        details: { schema_version: SCHEMA_VERSION },
   345→      },
   346→    },
   347→    { status }
   348→  );
   349→}
