"use client";

import { StickyNote, Type, Shapes, Hand, MoreHorizontal, MousePointer2 } from "lucide-react";
import { motion } from "framer-motion";
import { useEffect, useState } from "react";
import { useLanguageStore } from "@/store/language-store";
import { cn } from "@/lib/utils";

interface CanvasBoardProps {
    projectId: string;
}

export function CanvasBoard({ projectId }: CanvasBoardProps) {
    const { t } = useLanguageStore();
    const [ideaContext, setIdeaContext] = useState(t.workspace.canvas.loading);

    useEffect(() => {
        if (typeof window !== "undefined") {
            const storedIdea = localStorage.getItem("k3rn_current_idea");
            if (storedIdea && storedIdea.length > 5) {
                setIdeaContext(
                    storedIdea.substring(0, 100) + (storedIdea.length > 100 ? "..." : "")
                );
            } else {
                setIdeaContext(t.workspace.canvas.defaultContext);
            }
        }
    }, [t]);

    return (
        <main className="flex-1 bg-[#1a1c22] relative overflow-hidden cursor-crosshair">
            {/* Grid Pattern Background */}
            <div
                className="absolute inset-0 z-0 opacity-20 pointer-events-none"
                style={{
                    backgroundImage: `radial-gradient(circle, #3A3D45 1px, transparent 1px)`,
                    backgroundSize: '24px 24px'
                }}
            />

            {/* Floating Toolbar */}
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-[#2F323A]/90 backdrop-blur-md border border-[#3A3D45] rounded-full px-6 py-3 flex items-center gap-6 z-30 transition-all hover:scale-105">
                <button className="p-2.5 bg-[#F75105] text-white rounded-full hover:bg-[#F78E21] transition-colors relative group">
                    <MousePointer2 className="w-5 h-5 fill-current" />
                    <span className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">Select</span>
                </button>
                <div className="h-6 w-[1px] bg-[#3A3D45]" />
                <button className="p-2 text-gray-400 hover:text-white transition-colors relative group">
                    <StickyNote className="w-5 h-5" />
                    <span className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">Note</span>
                </button>
                <button className="p-2 text-gray-400 hover:text-white transition-colors relative group">
                    <Type className="w-5 h-5" />
                    <span className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">Text</span>
                </button>
                <button className="p-2 text-gray-400 hover:text-white transition-colors relative group">
                    <Shapes className="w-5 h-5" />
                    <span className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">Shape</span>
                </button>
                <div className="h-6 w-[1px] bg-[#3A3D45]" />
                <button className="p-2 text-gray-400 hover:text-white transition-colors relative group">
                    <Hand className="w-5 h-5" />
                    <span className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">Pan</span>
                </button>
            </div>

            {/* Draggable Sticky Note 1 */}
            <motion.div
                drag
                dragMomentum={false}
                className="absolute top-24 left-24 w-72 p-5 bg-[#2F323A] border border-[#3A3D45] rounded-[var(--radius-2xl)] hover:border-[#F75105] transition-all cursor-move group z-10"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
            >
                <div className="flex justify-between items-start mb-3">
                    <div className="flex items-center gap-2">
                        <div className="w-2 h-2 rounded-full bg-[#F75105]" />
                        <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">
                            {t.workspace.canvas.coreAxiom}
                        </span>
                    </div>
                    <button className="text-gray-500 hover:text-white opacity-0 group-hover:opacity-100 transition-opacity">
                        <MoreHorizontal className="w-4 h-4" />
                    </button>
                </div>
                <p className="text-sm font-medium text-gray-200 leading-relaxed font-sans">{ideaContext}</p>
            </motion.div>

            {/* Draggable Sticky Note 2 (Opportunity) */}
            <motion.div
                drag
                dragMomentum={false}
                className="absolute top-64 left-[450px] w-64 p-5 bg-[#2F323A] border-l-4 border-l-emerald-500 rounded-[var(--radius-2xl)] hover:bg-[#3A3D45] transition-all cursor-move group z-10"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
            >
                <div className="flex justify-between mb-3">
                    <span className="text-[10px] uppercase font-bold text-emerald-500 tracking-wider">
                        {t.workspace.canvas.opportunity}
                    </span>
                </div>
                <p className="text-sm text-gray-300 leading-snug font-sans">
                    Potential asymmetry identified in user adoption curve specifically for early-stage founders.
                </p>
            </motion.div>

            {/* Draggable Sticky Note 3 (Tags) */}
            <motion.div
                drag
                dragMomentum={false}
                className="absolute top-[350px] left-[200px] w-auto px-4 py-2 bg-[#1a1c22] border border-[#3A3D45] rounded-full hover:border-[#F75105] transition-all cursor-move -rotate-3 hover:rotate-0 z-0"
                whileHover={{ scale: 1.05 }}
            >
                <p className="text-xs text-[#F75105] font-mono font-medium">
                    #scalability #infrastructure
                </p>
            </motion.div>
        </main>
    );
}

