     1→/**
     2→ * K3RN.LABS — Types TypeScript pour l'analyse d'idées
     3→ * Alignés strictement sur les JSON Schemas canoniques v1.0
     4→ */
     5→
     6→import type { AnalysisAxis } from './constants';
     7→
     8→// ═══════════════════════════════════════════════════════════════════
     9→// INPUT TYPES (analysis-input-v1.0.schema.json)
    10→// ═══════════════════════════════════════════════════════════════════
    11→
    12→export interface AnalysisInputMeta {
    13→  schema_version: '1.0';
    14→  request_id: string;
    15→  timestamp: string;
    16→  language: string;
    17→}
    18→
    19→export interface AnalysisInputIdea {
    20→  idea_id: string;
    21→  state: 'CAPTURED' | 'ANALYZED' | 'ENRICHED';
    22→}
    23→
    24→export interface AnalysisInputText {
    25→  content: string;
    26→  source: 'typed' | 'voice_transcript' | 'imported';
    27→  length: number;
    28→}
    29→
    30→export interface AnalysisInputLink {
    31→  url: string;
    32→  type: 'web' | 'social' | 'doc';
    33→}
    34→
    35→export interface AnalysisInputFile {
    36→  file_id: string;
    37→  type: 'pdf' | 'image' | 'text';
    38→  size_kb: number;
    39→}
    40→
    41→export interface AnalysisInputs {
    42→  text?: AnalysisInputText;
    43→  links?: AnalysisInputLink[];
    44→  files?: AnalysisInputFile[];
    45→}
    46→
    47→export interface AnalysisInputContext {
    48→  user_id: string;
    49→  experience_level?: 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED';
    50→  previous_ideas_count?: number;
    51→}
    52→
    53→export interface AnalysisInput {
    54→  meta: AnalysisInputMeta;
    55→  idea: AnalysisInputIdea;
    56→  inputs: AnalysisInputs;
    57→  context?: AnalysisInputContext;
    58→}
    59→
    60→// ═══════════════════════════════════════════════════════════════════
    61→// OUTPUT TYPES (analysis-output-v1.0.schema.json)
    62→// ═══════════════════════════════════════════════════════════════════
    63→
    64→export interface AnalysisOutputMeta {
    65→  schema_version: '1.0';
    66→  analysis_id: string;
    67→  timestamp: string;
    68→  orchestrator_version: string;
    69→  model: string;
    70→}
    71→
    72→export interface AnalysisOutputIdea {
    73→  idea_id: string;
    74→  title: string;
    75→  raw_summary: string;
    76→  inputs_used: ('text' | 'voice' | 'link' | 'file')[];
    77→}
    78→
    79→export interface AxisAnalysis {
    80→  score: number;
    81→  justification: string;
    82→  blocking_gap: boolean;
    83→}
    84→
    85→export interface AnalysisAxes {
    86→  problem: AxisAnalysis;
    87→  market: AxisAnalysis;
    88→  differentiation: AxisAnalysis;
    89→  feasibility: AxisAnalysis;
    90→  business: AxisAnalysis;
    91→  founder_fit: AxisAnalysis;
    92→}
    93→
    94→export interface AnalysisScores {
    95→  global_score: number;
    96→  weights: Record<AnalysisAxis, number>;
    97→}
    98→
    99→export interface AnalysisDecision {
   100→  recommendation: 'GO' | 'EXPLORE' | 'PARK' | 'KILL';
   101→  confidence_level: 'LOW' | 'MEDIUM' | 'HIGH';
   102→  summary: string;
   103→}
   104→
   105→export interface AnalysisRisk {
   106→  axis: AnalysisAxis;
   107→  description: string;
   108→  severity: 'LOW' | 'MEDIUM' | 'HIGH';
   109→}
   110→
   111→export interface AnalysisLever {
   112→  axis: AnalysisAxis;
   113→  action: string;
   114→  expected_impact: 'LOW' | 'MEDIUM' | 'HIGH';
   115→}
   116→
   117→export interface AnalysisEnrichment {
   118→  required: boolean;
   119→  trigger_axes: AnalysisAxis[];
   120→  max_questions: number;
   121→}
   122→
   123→export interface LabOrientation {
   124→  recommended: boolean;
   125→  lab: 'DISCOVERY' | 'MARKET' | 'STRATEGY' | 'TECH' | 'BUSINESS' | 'NONE';
   126→  reason: string;
   127→}
   128→
   129→export interface AnalysisOutput {
   130→  meta: AnalysisOutputMeta;
   131→  idea: AnalysisOutputIdea;
   132→  analysis: AnalysisAxes;
   133→  scores: AnalysisScores;
   134→  decision: AnalysisDecision;
   135→  risks: AnalysisRisk[];
   136→  levers: AnalysisLever[];
   137→  enrichment: AnalysisEnrichment;
   138→  lab_orientation: LabOrientation;
   139→}
   140→
   141→// ═══════════════════════════════════════════════════════════════════
   142→// ENRICHMENT TYPES (Contrat Questions Guidées v1.1 + Widget Schema v1.0)
   143→// ═══════════════════════════════════════════════════════════════════
   144→
   145→export interface QuestionOption {
   146→  id: string;
   147→  label: string;
   148→  value: string;
   149→  score_adjustment: number;
   150→}
   151→
   152→export interface QuestionExpectedImpact {
   153→  axis: AnalysisAxis;
   154→  min_adjustment: number;
   155→  max_adjustment: number;
   156→}
   157→
   158→export interface EnrichmentQuestion {
   159→  question_id: string;
