   164→  allow_skip: boolean;
   165→  timeout_seconds: number;
   166→  expected_impact: QuestionExpectedImpact;
   167→}
   168→
   169→export interface EnrichmentResponse {
   170→  question_id: string;
   171→  status: 'completed' | 'skipped' | 'skipped_timeout';
   172→  selected_option_ids?: string[];
   173→  response_time_seconds?: number;
   174→}
   175→
   176→export interface EnrichmentRequest {
