/**
 * K3RN.LABS — Types TypeScript pour l'analyse d'idées
 * Alignés strictement sur les JSON Schemas canoniques v1.0
 */

import type { AnalysisAxis } from './constants';

// ═══════════════════════════════════════════════════════════════════
// INPUT TYPES (analysis-input-v1.0.schema.json)
// ═══════════════════════════════════════════════════════════════════

export interface AnalysisInputMeta {
  schema_version: '1.0';
  request_id: string;
  timestamp: string;
  language: string;
}

export interface AnalysisInputIdea {
  idea_id: string;
  state: 'CAPTURED' | 'ANALYZED' | 'ENRICHED';
}

export interface AnalysisInputText {
  content: string;
  source: 'typed' | 'voice_transcript' | 'imported';
  length: number;
}

export interface AnalysisInputLink {
  url: string;
  type: 'web' | 'social' | 'doc';
}

export interface AnalysisInputFile {
  file_id: string;
  type: 'pdf' | 'image' | 'text';
  size_kb: number;
}

export interface AnalysisInputs {
  text?: AnalysisInputText;
  links?: AnalysisInputLink[];
  files?: AnalysisInputFile[];
}

export interface AnalysisInputContext {
  user_id: string;
  experience_level?: 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED';
  previous_ideas_count?: number;
}

export interface AnalysisInput {
  meta: AnalysisInputMeta;
  idea: AnalysisInputIdea;
  inputs: AnalysisInputs;
  context?: AnalysisInputContext;
}

// ═══════════════════════════════════════════════════════════════════
// OUTPUT TYPES (analysis-output-v1.0.schema.json)
// ═══════════════════════════════════════════════════════════════════

export interface AnalysisOutputMeta {
  schema_version: '1.0';
  analysis_id: string;
  timestamp: string;
  orchestrator_version: string;
  model: string;
}

export interface AnalysisOutputIdea {
  idea_id: string;
  title: string;
  raw_summary: string;
  inputs_used: ('text' | 'voice' | 'link' | 'file')[];
}

export interface AxisAnalysis {
  score: number;
  justification: string;
  blocking_gap: boolean;
}

export interface AnalysisAxes {
  problem: AxisAnalysis;
  market: AxisAnalysis;
  differentiation: AxisAnalysis;
  feasibility: AxisAnalysis;
  business: AxisAnalysis;
  founder_fit: AxisAnalysis;
}

export interface AnalysisScores {
  global_score: number;
  weights: Record<AnalysisAxis, number>;
}

export interface AnalysisDecision {
  recommendation: 'GO' | 'EXPLORE' | 'PARK' | 'KILL';
  confidence_level: 'LOW' | 'MEDIUM' | 'HIGH';
  summary: string;
}

export interface AnalysisRisk {
  axis: AnalysisAxis;
  description: string;
  severity: 'LOW' | 'MEDIUM' | 'HIGH';
}

export interface AnalysisLever {
  axis: AnalysisAxis;
  action: string;
  expected_impact: 'LOW' | 'MEDIUM' | 'HIGH';
}

export interface AnalysisEnrichment {
  required: boolean;
  trigger_axes: AnalysisAxis[];
  max_questions: number;
}

export interface LabOrientation {
  recommended: boolean;
  lab: 'DISCOVERY' | 'MARKET' | 'STRATEGY' | 'TECH' | 'BUSINESS' | 'NONE';
  reason: string;
}

export interface AnalysisOutput {
  meta: AnalysisOutputMeta;
  idea: AnalysisOutputIdea;
  analysis: AnalysisAxes;
  scores: AnalysisScores;
  decision: AnalysisDecision;
  risks: AnalysisRisk[];
  levers: AnalysisLever[];
  enrichment: AnalysisEnrichment;
  lab_orientation: LabOrientation;
}

// ═══════════════════════════════════════════════════════════════════
// ENRICHMENT TYPES (Contrat Questions Guidées v1.1 + Widget Schema v1.0)
// ═══════════════════════════════════════════════════════════════════

export interface QuestionOption {
  id: string;
  label: string;
  value: string;
  score_adjustment: number;
}

export interface QuestionExpectedImpact {
  axis: AnalysisAxis;
  min_adjustment: number;
  max_adjustment: number;
}

export interface EnrichmentQuestion {
  question_id: string;
  axis: AnalysisAxis;
  type: 'single_select' | 'multi_select' | 'range' | 'ranking';
  prompt: string;
  options: QuestionOption[];
  allow_skip: boolean;
  timeout_seconds: number;
  expected_impact: QuestionExpectedImpact;
}

export interface EnrichmentResponse {
  question_id: string;
  status: 'completed' | 'skipped' | 'skipped_timeout';
  selected_option_ids?: string[];
  response_time_seconds?: number;
}

export interface EnrichmentRequest {
  idea_id: string;
  analysis_id: string;
  analysis: AnalysisAxes;
  scores: AnalysisScores;
  decision: AnalysisDecision;
}

export interface EnrichmentResult {
  enrichment_id: string;
  idea_id: string;
  timestamp: string;
  questions: EnrichmentQuestion[];
  trigger_axes: AnalysisAxis[];
}

export interface EnrichmentSubmission {
  enrichment_id: string;
  idea_id: string;
  responses: EnrichmentResponse[];
}

export interface EnrichmentRecalculation {
  enrichment_id: string;
  idea_id: string;
  timestamp: string;
  scores_before: Record<string, number>;
  scores_after: Record<string, number>;
  decision_before: string;
  decision_after: string;
  confidence_before: string;
  confidence_after: string;
  adjustments: Array<{
    axis: AnalysisAxis;
    question_id: string;
    adjustment: number;
  }>;
}

// ═══════════════════════════════════════════════════════════════════
// API ERROR TYPES
// ═══════════════════════════════════════════════════════════════════

export interface ApiError {
  error: {
    code: string;
    message: string;
    details?: unknown;
  };
}

/**
 * K3RN.LABS — Constantes canoniques pour l'analyse d'idées
 * Source de vérité : Contrat Canonique Analyse Idée v1.1
 */

// ─── Axes canoniques ─────────────────────────────────────────────
export const ANALYSIS_AXES = [
  'problem',
  'market',
  'differentiation',
  'feasibility',
  'business',
  'founder_fit',
] as const;

export type AnalysisAxis = (typeof ANALYSIS_AXES)[number];

// ─── Pondérations canoniques (Section 4.2) ───────────────────────
export const CANONICAL_WEIGHTS: Record<AnalysisAxis, number> = {
  problem: 0.2,
  market: 0.2,
  differentiation: 0.15,
  feasibility: 0.15,
  business: 0.2,
  founder_fit: 0.1,
} as const;

// ─── Axes critiques (Problème, Marché, Business) ─────────────────
export const CRITICAL_AXES: AnalysisAxis[] = ['problem', 'market', 'business'];

// ─── Seuils de décision (Section 5.1) ────────────────────────────
export const DECISION_THRESHOLDS = {
  KILL_SCORE: 30,
  KILL_PROBLEM_MIN: 20,
  PARK_MIN: 30,
  PARK_MAX: 50,
  PARK_CRITICAL_MIN: 25,
  EXPLORE_MIN: 50,
  EXPLORE_MAX: 70,
  GO_MIN: 70,
  GO_CRITICAL_MIN: 50,
} as const;

// ─── Seuils d'enrichissement (Contrat Questions Guidées v1.1, Section 3.1) ──
export const ENRICHMENT_THRESHOLDS = {
  AXIS_SCORE_MIN: 40,
  GLOBAL_SCORE_MIN: 50,
  GLOBAL_SCORE_MAX: 70,
} as const;

// ─── Limites d'enrichissement (Section 7.1) ──────────────────────
export const ENRICHMENT_LIMITS = {
  MAX_AXES: 2,
  MAX_QUESTIONS_PER_AXIS: 3,
  MAX_QUESTIONS_PER_SEQUENCE: 5,
  TIMEOUT_SECONDS: 90,
  TARGET_COMPLETION_SECONDS: 60,
} as const;

// ─── Plage d'ajustement de score (Section 8.2) ──────────────────
export const SCORE_ADJUSTMENT_RANGE = {
  SMALL: { min: 5, max: 15 },
  MEDIUM: { min: 15, max: 30 },
  LARGE: { min: 30, max: 50 },
} as const;

// ─── Score range ─────────────────────────────────────────────────
export const SCORE_RANGE = {
  MIN: 0,
  MAX: 100,
} as const;

// ─── Schema version ─────────────────────────────────────────────
export const SCHEMA_VERSION = '1.0' as const;

// ─── Enums canoniques ────────────────────────────────────────────
export const IDEA_STATES = ['CAPTURED', 'ANALYZED', 'ENRICHED'] as const;
export const DECISIONS = ['GO', 'EXPLORE', 'PARK', 'KILL'] as const;
export const CONFIDENCE_LEVELS = ['LOW', 'MEDIUM', 'HIGH'] as const;
export const SEVERITIES = ['LOW', 'MEDIUM', 'HIGH'] as const;
export const TEXT_SOURCES = ['typed', 'voice_transcript', 'imported'] as const;
export const LINK_TYPES = ['web', 'social', 'doc'] as const;
export const FILE_TYPES = ['pdf', 'image', 'text'] as const;
export const INPUTS_USED = ['text', 'voice', 'link', 'file'] as const;
export const LABS = ['DISCOVERY', 'MARKET', 'STRATEGY', 'TECH', 'BUSINESS', 'NONE'] as const;
export const EXPERIENCE_LEVELS = ['BEGINNER', 'INTERMEDIATE', 'ADVANCED'] as const;
export const QUESTION_TYPES = ['single_select', 'multi_select', 'range', 'ranking'] as const;

