"use client";

import { useEffect, useState } from "react";
import { cn } from "@/lib/utils";
import { RotateCcw, LayoutDashboard, ArrowRight, AlertTriangle, Zap, Sparkles, FolderOpen } from "lucide-react";
import { Button } from "@/components/ui/button";
import { K3rnLogo } from "@/components/ui/k3rn-logo";
import { useRouter } from "next/navigation";
import { toast } from "sonner";
import { useLanguageStore } from "@/store/language-store";
import { buildCanonicalInput } from "@/lib/analysis/build-canonical-input";
import { DecisionBadge } from "@/components/ui/decision-badge";
import { AxisScoreBar } from "@/components/ui/axis-score-bar";
import { EnrichmentFlow } from "@/components/capture/enrichment-flow";
import type { AnalysisOutput, AnalysisAxes } from "@/lib/analysis/types";

const AXIS_KEYS = ["problem", "market", "differentiation", "feasibility", "business", "founder_fit"] as const;

interface Props {
    isActive: boolean;
    onReset: () => void;
    inputData: { text: string; files: any[]; links: string[] };
    isVoice?: boolean;
}

export function AnalysisResults({ isActive, onReset, inputData, isVoice }: Props) {
    const router = useRouter();
    const { t, currentLang } = useLanguageStore();
    const [step, setStep] = useState(0);
    const [logs, setLogs] = useState<string[]>([]);
    const [showResult, setShowResult] = useState(false);
    const [result, setResult] = useState<AnalysisOutput | null>(null);
    const [isDemoMode, setIsDemoMode] = useState(false);
    const [showEnrichment, setShowEnrichment] = useState(false);

    const axisSteps = AXIS_KEYS.map((key) => ({
        id: key,
        name: (t?.analysis?.axes as any)?.[key] || key.charAt(0).toUpperCase() + key.slice(1).replace("_", " "),
    }));

    const getDemoResult = (): AnalysisOutput => {
        const d = (t?.analysis as any)?.demoResult;
        return {
            meta: {
                schema_version: "1.0",
                analysis_id: crypto.randomUUID(),
                timestamp: new Date().toISOString(),
                orchestrator_version: "v1.0",
                model: "demo",
            },
            idea: {
                idea_id: crypto.randomUUID(),
                title: d?.title || "AI-powered No-Code SaaS Platform",
                raw_summary: d?.summary || "Platform leveraging AI for rapid no-code application development.",
                inputs_used: ["text"],
            },
            analysis: {
                problem: { score: 78, justification: d?.axes?.problem || "Clear problem identified with strong market pain point.", blocking_gap: false },
                market: { score: 72, justification: d?.axes?.market || "Large addressable market with growing demand for no-code solutions.", blocking_gap: false },
                differentiation: { score: 55, justification: d?.axes?.differentiation || "AI differentiation exists but competitive landscape is crowded.", blocking_gap: false },
                feasibility: { score: 82, justification: d?.axes?.feasibility || "Next.js + Supabase stack is optimal for rapid MVP delivery.", blocking_gap: false },
                business: { score: 60, justification: d?.axes?.business || "Revenue model needs refinement. CAC/LTV ratio assumes viral growth.", blocking_gap: true },
                founder_fit: { score: 70, justification: d?.axes?.founder_fit || "Technical founder with relevant domain experience.", blocking_gap: false },
            },
            scores: {
                global_score: 70,
                weights: { problem: 0.2, market: 0.2, differentiation: 0.15, feasibility: 0.15, business: 0.2, founder_fit: 0.1 },
            },
            decision: {
                recommendation: "EXPLORE",
                confidence_level: "MEDIUM",
                summary: d?.decisionSummary || "Strong technical foundation with clear market opportunity. Business model refinement needed before full commitment.",
            },
            risks: [
                { axis: "business", description: d?.risks?.[0] || "Revenue model depends on unvalidated viral growth assumptions.", severity: "HIGH" },
                { axis: "differentiation", description: d?.risks?.[1] || "Crowded competitive landscape may erode differentiation.", severity: "MEDIUM" },
            ],
            levers: [
                { axis: "business", action: d?.levers?.[0] || "Validate pricing with 50 early adopters before launch.", expected_impact: "HIGH" },
                { axis: "differentiation", action: d?.levers?.[1] || "Patent or open-source the core AI engine to create moat.", expected_impact: "MEDIUM" },
            ],
            enrichment: { required: true, trigger_axes: ["business", "differentiation"], max_questions: 4 },
            lab_orientation: { recommended: true, lab: "BUSINESS", reason: "Business model needs validation." },
        };
    };

    const addLog = (msg: string) => setLogs((prev) => [...prev.slice(-6), `> ${msg}`]);
    const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

    useEffect(() => {
        if (!isActive) {
            setStep(0);
            setLogs([]);
            setShowResult(false);
            setResult(null);
            setIsDemoMode(false);
            setShowEnrichment(false);
            return;
        }

        const runAnalysis = async () => {
            setIsDemoMode(false);

            addLog(t?.analysis?.logs?.init || "Initialising Sequence...");
            await delay(800);

            // Build canonical input
            const canonicalInput = buildCanonicalInput({
                text: inputData.text,
                files: inputData.files.map((f: any) => ({ name: f.name, type: f.type, size: f.size })),
                links: inputData.links,
                isVoice,
                lang: currentLang.toLowerCase(),
            });

            // Fire API call
            const apiCall = fetch("/api/analysis", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(canonicalInput),
            }).then(async (res) => {
                const data = await res.json();
                if (res.status === 429) throw new Error("QUOTA_EXCEEDED");
                if (!res.ok) throw new Error(data.error?.message || "Analysis failed");
                return data as AnalysisOutput;
            });

            // Animate 6 canonical axes
            for (let i = 0; i < axisSteps.length; i++) {
                setStep(i + 1);
                addLog(`[AXIS_${(i + 1).toString().padStart(2, "0")}] ${t?.analysis?.logs?.analyzing || "Analyzing"}: ${axisSteps[i].name}...`);
                await delay(300 + Math.random() * 400);
            }

            addLog(t?.analysis?.logs?.computing || "Computing Global Score...");

            try {
                const data = await apiCall;
                setResult(data);
            } catch (error: any) {
                console.warn("Analysis API failed:", error);
                if (error.message === "QUOTA_EXCEEDED") {
                    addLog(t?.analysis?.logs?.quotaWarning || "Quota Exceeded");
                    setIsDemoMode(true);
                    setResult(getDemoResult());
                    toast.warning(t?.analysis?.logs?.demoMode || "Demo Mode", {
                        description: t?.analysis?.logs?.demoDesc || "Quota reached",
                    });
                } else {
                    addLog(t?.analysis?.logs?.error || "Critical Error");
                    setIsDemoMode(true);
                    setResult(getDemoResult());
                    toast.error(t?.analysis?.logs?.analysisFailed || "Analysis Failed", {
                        description: error.message,
                    });
                }
            }

            await delay(500);
            setShowResult(true);
        };

        runAnalysis();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isActive]);

    const saveProjectToStorage = () => {
        if (!result) return;

        // Generate concise title (max 60 chars) and structured description
        const fullText = inputData.text || result.idea.title;
        const generatedTitle = result.idea.title && result.idea.title.length <= 60
            ? result.idea.title
            : fullText.slice(0, 60).trim() + (fullText.length > 60 ? "..." : "");

        const generatedDescription = result.idea.raw_summary || fullText;

        const workspaceData = {
            id: result.idea.idea_id,
            title: generatedTitle,
            text: fullText,
            description: generatedDescription,
            globalScore: result.scores.global_score,
            recommendation: result.decision.recommendation,
            confidenceLevel: result.decision.confidence_level,
            analysis: {
                axes: AXIS_KEYS.map((key) => ({
                    label: key.charAt(0).toUpperCase() + key.slice(1).replace("_", " "),
                    score: result.analysis[key].score,
                    justification: result.analysis[key].justification
                })),
                synthesis: result.decision.summary,
                risks: result.risks.map(r => r.description)
            },
            timestamp: new Date().toISOString(),
            isDemo: isDemoMode,
            fullResult: result,
        };
        localStorage.setItem("k3rn_active_project", JSON.stringify(workspaceData));
    };

    const handleEnterLab = () => {
        if (!result) return;
        saveProjectToStorage();
        router.push(`/workspace/${result.idea.idea_id}`);
    };

    const handleGoToDossiers = () => {
        saveProjectToStorage();
        router.push("/workspace");
    };

    const handleEnrichmentComplete = (updatedResult: any) => {
        if (result && updatedResult) {
            const updated: AnalysisOutput = {
                ...result,
                analysis: updatedResult.updated_analysis ?? result.analysis,
                scores: updatedResult.updated_scores ?? result.scores,
                decision: {
                    ...result.decision,
                    recommendation: updatedResult.decision_after?.recommendation ?? result.decision.recommendation,
                    confidence_level: updatedResult.decision_after?.confidence_level ?? result.decision.confidence_level,
                },
                enrichment: { ...result.enrichment, required: false },
            };
            setResult(updated);
        }
        setShowEnrichment(false);
    };

    if (!isActive) return null;

    // Enrichment flow view
    if (showEnrichment && result) {
        return (
            <div className="w-full max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700 ease-out">
                <EnrichmentFlow
                    analysis={result.analysis}
                    scores={result.scores}
                    decision={result.decision}
                    ideaId={result.idea.idea_id}
                    ideaSummary={result.idea.raw_summary}
                    onComplete={handleEnrichmentComplete}
                    onCancel={() => setShowEnrichment(false)}
                />
            </div>
        );
    }

    return (
        <div className="w-full max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700 ease-out">
            {!showResult ? (
                // LOADING STATE - ULTRA PREMIUM
                // LOADING STATE - BRAND ALIGNED
                <div className="bg-[#22242B] rounded-2xl p-12 border border-white/5 flex flex-col items-center justify-center min-h-[420px] relative overflow-hidden w-full max-w-[480px] mx-auto">

                    <div className="flex flex-col items-center gap-8 z-10 w-full relative">
                        {/* Logo Container with Pulse */}
                        <div className="relative">
                            <div className="absolute inset-0 bg-[#F75105]/5 blur-[60px] rounded-full animate-pulse" />
                            <div className="relative z-10 p-6 rounded-full bg-[#1A1C22] border border-white/5">
                                <K3rnLogo size="md" className="animate-[spin-rhythm_4s_ease-in-out_infinite] opacity-90" />
                            </div>
                        </div>

                        {/* Text Content */}
                        <div className="flex flex-col items-center gap-3 text-center">
                            <h2 className="text-xs font-bold text-white tracking-[0.2em] uppercase font-mono">
                                {t?.analysis?.title || "Traitement K3RN"}
                            </h2>
                            <p className="text-[11px] text-[#A0A3AB] font-sans tracking-wide">
                                {(t?.analysis as any)?.processing || "Analyse de structure en cours..."}
                            </p>
                        </div>

                        {/* Progress Bar */}
                        <div className="w-full max-w-[200px] h-1 bg-[#1A1C22] rounded-full overflow-hidden">
                            <div
                                className="h-full bg-[#F75105] transition-all duration-500 ease-out rounded-full"
                                style={{ width: `${(step / axisSteps.length) * 100}%` }}
                            />
                        </div>

                        {/* Minimalist Logs */}
                        <div className="h-8 flex items-center justify-center">
                            <p key={logs.length} className="text-[10px] font-mono text-[#6C6F78] animate-in fade-in slide-in-from-bottom-1 duration-300">
                                {logs[logs.length - 1]?.replace(/^> /, '')}
                            </p>
                        </div>
                    </div>
                </div>
            ) : result ? (
                // RESULT STATE
                <div className="bg-[#2C2F38] rounded-xl border-0 overflow-hidden ring-1 ring-white/5 animate-in zoom-in-95 duration-500">
                    <div className="grid md:grid-cols-[280px_1fr] h-full min-h-[500px]">

                        {/* Sidebar: Score + Decision */}
                        <div className="bg-[#22242B] p-8 flex flex-col items-center justify-center text-center gap-6 border-r border-white/5 relative">
                            {isDemoMode && (
                                <div className="absolute top-0 left-0 w-full bg-[#F75105]/10 text-[#F75105] text-[10px] py-1 font-bold tracking-widest uppercase text-center">
                                    {t?.analysis?.simulated || "Simulated"}
                                </div>
                            )}

                            <div>
                                <span className="text-gray-500 text-[10px] uppercase tracking-widest font-bold">
                                    {t?.analysis?.globalScore || "Global Score"}
                                </span>
                                <div className={cn(
                                    "text-7xl font-sans font-bold tracking-tighter mt-2",
                                    result.scores.global_score >= 70 ? "text-white" : "text-gray-400"
                                )}>
                                    {result.scores.global_score}
                                </div>
                            </div>

                            <DecisionBadge decision={result.decision.recommendation} />

                            <div className="text-[10px] text-gray-500 uppercase tracking-widest">
                                {t?.analysis?.confidence || "Confidence"}: {result.decision.confidence_level}
                            </div>
                        </div>

                        {/* Main Content */}
                        <div className="p-8 flex flex-col bg-[#2C2F38]">
                            <div className="flex-1 space-y-8">
                                {/* Dossier Header */}
                                <div className="mb-6">
                                    <div className="text-[10px] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-2">DOSSIER</div>
                                    <h2 className="text-2xl font-semibold text-white mb-3">{result.idea.title}</h2>
                                    <p className="text-sm text-[--color-text-secondary] leading-relaxed">
                                        {result.idea.raw_summary}
                                    </p>
                                </div>

                                {/* Decision Summary */}
                                <div>
                                    <h3 className="text-lg font-medium text-white mb-3 flex items-center gap-2">
                                        <ArrowRight className="w-4 h-4 text-[#F75105]" />
                                        {t?.analysis?.verdict || "Analysis Verdict"}
                                    </h3>
                                    <p className="text-gray-300 text-sm leading-relaxed pl-6 border-l-2 border-[#3A3D45]">
                                        &ldquo;{result.decision.summary}&rdquo;
                                    </p>
                                </div>

                                {/* 6 Axis Cards */}
                                <div className="space-y-3">
                                    <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4">
                                        {t?.analysis?.axisBreakdown || "Axis Breakdown"}
                                    </h4>
                                    {AXIS_KEYS.map((axis) => {
                                        const data = result.analysis[axis];
                                        const axisLabel = (t?.analysis?.axes as any)?.[axis] || axis.replace("_", " ");
                                        return (
                                            <div key={axis} className="p-4 rounded-lg bg-[#22242B]/50 border border-white/5 hover:border-[#F75105]/30 transition-colors group">
                                                <AxisScoreBar
                                                    label={axisLabel}
                                                    score={data.score}
                                                    blockingGap={data.blocking_gap}
                                                />
                                                <p className="text-xs text-gray-400 mt-2 pl-[140px] leading-relaxed">
                                                    {data.justification}
                                                </p>
                                            </div>
                                        );
                                    })}
                                </div>

                                {/* Risks */}
                                {result.risks.length > 0 && (
                                    <div>
                                        <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
                                            <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
                                            {t?.analysis?.risks || "Risks"}
                                        </h4>
                                        <ul className="list-none space-y-2">
                                            {result.risks.map((risk, i) => (
                                                <li key={i} className="flex items-start gap-3 text-sm text-[--color-text-secondary] leading-relaxed">
                                                    <div className="w-1.5 h-1.5 rounded-full bg-[--color-brand-primary] mt-[7px] shrink-0" />
                                                    <span>{risk.description}</span>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}

                                {/* Levers */}
                                {result.levers.length > 0 && (
                                    <div>
                                        <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
                                            <Zap className="w-3.5 h-3.5 text-amber-400" />
                                            {t?.analysis?.levers || "Growth Levers"}
                                        </h4>
                                        <div className="space-y-2">
                                            {result.levers.map((lever, i) => (
                                                <div key={i} className="flex items-start gap-3 text-sm text-gray-400 pl-4 border-l-2 border-amber-500/20">
                                                    <span className={cn(
                                                        "text-[10px] font-bold uppercase tracking-wider shrink-0 mt-0.5",
                                                        lever.expected_impact === "HIGH" ? "text-emerald-400" : lever.expected_impact === "MEDIUM" ? "text-amber-400" : "text-gray-500"
                                                    )}>
                                                        {lever.expected_impact}
                                                    </span>
                                                    <span>{lever.action}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Actions */}
                            <div className="pt-8 mt-6 flex flex-wrap gap-4 border-t border-white/10">
                                <Button
                                    onClick={onReset}
                                    variant="ghost"
                                    className="text-gray-400 hover:text-white hover:bg-white/5"
                                >
                                    <RotateCcw className="w-4 h-4 mr-2" />
                                    {t?.analysis?.newAnalysis || "Nouveau scan"}
                                </Button>

                                <div className="flex-1" />

                                {result.enrichment?.required && !isDemoMode && (
                                    <Button
                                        onClick={() => setShowEnrichment(true)}
                                        variant="outline"
                                        className="border-[#F75105]/30 text-[#F75105] hover:bg-[#F75105]/10 hover:text-[#F78E21]"
                                    >
                                        <Sparkles className="w-4 h-4 mr-2" />
                                        {t?.analysis?.enrichmentAvailable || "Enrichir l'analyse"}
                                    </Button>
                                )}

                                <Button
                                    onClick={handleGoToDossiers}
                                    variant="outline"
                                    className="border-white/10 text-[#D2D3D4] hover:bg-white/5 hover:text-white rounded-lg px-5"
                                >
                                    <FolderOpen className="w-4 h-4 mr-2" />
                                    {t?.analysis?.myDossiers || "Sauvegarder et quitter"}
                                </Button>

                                <Button
                                    onClick={handleEnterLab}
                                    className="bg-[#F75105] hover:bg-[#F78E21] text-white font-medium rounded-lg px-6 shadow-lg shadow-[#F75105]/20 hover:scale-[1.02] transition-all"
                                >
                                    <LayoutDashboard className="w-4 h-4 mr-2" />
                                    {t?.analysis?.enterLab || "Structurer le projet"}
                                </Button>
                            </div>
                        </div>
                    </div>
                </div>
            ) : null}
        </div>
    );
}

