     9→// In-memory conversation storage
    10→const conversations = new Map<string, Array<{ role: string; content: string }>>();
    11→
    12→export async function POST(request: NextRequest) {
    13→    try {
    14→        const formData = await request.formData();
    15→        const conversationId = formData.get('conversationId') as string;
    16→        const message = formData.get('message') as string;
    17→        const linksJson = formData.get('links') as string;
    18→        const links = linksJson ? JSON.parse(linksJson) : [];
    19→
    20→        // Get or initialize conversation history
    21→        let history = conversations.get(conversationId) || [];
    22→
    23→        // Build user message
    24→        let userContent = message;
    25→        if (links.length > 0) {
    26→            userContent += `\n\nLiens de référence: ${links.join(', ')}`;
    27→        }
    28→
    29→        history.push({
    30→            role: 'user',
    31→            content: userContent,
    32→        });
