export async function POST(req: Request) {
  try {
    const body: ChatRequest = await req.json();
    const { messages, projectContext, labType, language } = body;

    // Validation
    if (!messages || !Array.isArray(messages) || messages.length === 0) {
      return Response.json(
        { error: { code: "INVALID_INPUT", message: "Messages array required" } },
        { status: 400 }
      );
    }

    if (!projectContext || !labType) {
      return Response.json(
        { error: { code: "INVALID_INPUT", message: "projectContext and labType required" } },
        { status: 400 }
      );
    }

    // Build system prompt based on lab type
    const systemPrompt = labType === "discovery"
      ? buildDiscoverySystemPrompt(projectContext, language || "fr")
      : buildStructurationSystemPrompt(projectContext, language || "fr");

    // Stream response from Claude
    const stream = await anthropic.messages.stream({
      model: CHAT_MODEL,
      max_tokens: 1024,
      temperature: 0.7,
      system: systemPrompt,
      messages: messages.map(m => ({
        role: m.role,
        content: m.content,
      })),
    });

    // Return as a ReadableStream using the SDK's built-in streaming
    const encoder = new TextEncoder();
    const readableStream = new ReadableStream({
      async start(controller) {
        try {
          for await (const event of stream) {
            if (
              event.type === "content_block_delta" &&
              event.delta.type === "text_delta"
            ) {
              const chunk = `data: ${JSON.stringify({ text: event.delta.text })}\n\n`;
              controller.enqueue(encoder.encode(chunk));
            }
          }
          controller.enqueue(encoder.encode("data: [DONE]\n\n"));
          controller.close();
        } catch (error) {
          const err = error as Error;
          controller.enqueue(
            encoder.encode(`data: ${JSON.stringify({ error: err.message })}\n\n`)
          );
          controller.close();
        }
      },
    });

    return new Response(readableStream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        Connection: "keep-alive",
      },
    });
  } catch (error) {
    const err = error as Error & { status?: number };
    if (err.status === 429) {
      return Response.json(
        { error: { code: "AI_RATE_LIMITED", message: "Rate limit exceeded" } },
        { status: 429 }
      );
    }
    console.error("Expert chat error:", err);
    return Response.json(
      { error: { code: "INTERNAL_ERROR", message: err.message } },
      { status: 500 }
    );
  }
}
```

**Key design decisions:**
- Uses `anthropic.messages.stream()` for SSE-based streaming. The SDK at `^0.74.0` supports this method.
- The system prompt is built dynamically from project data, giving the AI full context about the analysis.
- Two distinct personas (Ava/Marcus) with completely different instructions, tone, and focus areas.
- Uses `claude-sonnet-4-20250514` by default for chat (cost-effective for conversational use). Configurable via env var `EXPERT_CHAT_MODEL`.
- SSE format (`data: {...}\n\n`) is standard for streaming frontends.
- The language from the i18n store is passed through so the AI responds in the correct language.

