#### STEP 2: `src/app/api/expert-chat/route.ts` (NEW)

**Purpose:** Server-side API endpoint for real AI expert chat, streaming responses from Claude.

**Dependencies:** `@anthropic-ai/sdk` (already in `package.json` at `^0.74.0`), `ANTHROPIC_API_KEY` (already in `.env.local`)

**Pattern reference:** The existing `/api/analysis/route.ts` shows how Claude is called in this project -- using `new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY })` and `anthropic.messages.create()`.

**Detailed specification:**

```typescript
// src/app/api/expert-chat/route.ts

import Anthropic from "@anthropic-ai/sdk";

const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

// Use a lighter model for chat (cost optimization)
const CHAT_MODEL = process.env.EXPERT_CHAT_MODEL || "claude-sonnet-4-20250514";

interface ChatMessage {
  role: "user" | "assistant";
  content: string;
}

interface ChatRequest {
  messages: ChatMessage[];
  projectContext: {
    title: string;
    description: string;
    globalScore: number;
    recommendation: string;
    confidenceLevel: string;
    axes: { label: string; score: number; justification: string }[];
    synthesis: string;
    risks: string[];
    levers?: { axis: string; action: string; expected_impact: string }[];
  };
  labType: "discovery" | "structuration";
  language: string; // "fr" | "en" | "es"
}

function buildDiscoverySystemPrompt(ctx: ChatRequest["projectContext"], lang: string): string {
  // Ava persona -- discovery expert
  const axesSummary = ctx.axes
    .map(a => `- ${a.label}: ${a.score}/100 ${a.score < 50 ? "[WEAK]" : ""}`)
    .join("\n");

  const weakAxes = ctx.axes.filter(a => a.score < 50);
  const risksStr = ctx.risks.map(r => `- ${r}`).join("\n");

  return `Tu es Ava, experte en Discovery chez K3RN.LABS. Tu accompagnes les entrepreneurs dont les projets sont en phase d'exploration (EXPLORE/PARK/DRAFT).

## TON RÔLE
- Poser des questions profondes et provocantes pour challenger les hypothèses
- Identifier les angles morts et les incertitudes non résolues
- Aider à formuler des hypothèses testables
- Guider vers la validation terrain (interviews, MVPs, prototypes)
- Tu ne donnes JAMAIS de réponse toute faite: tu questionnes, tu challenges

## STYLE
- Directe mais bienveillante
- Questions socratiques
- Tu utilises des analogies et des exemples concrets
- Tu fais des remarques incisives mais constructives
- Réponds toujours dans la langue: ${lang === "fr" ? "français" : lang === "es" ? "español" : "English"}
- Sois concise: max 3-4 phrases par message, sauf si la question nécessite plus de détail

## CONTEXTE DU PROJET
**${ctx.title}** (Score: ${ctx.globalScore}/100 — ${ctx.recommendation}, Confiance: ${ctx.confidenceLevel})

${ctx.description}

### Synthèse de l'Analyse
"${ctx.synthesis}"

### Détail des Axes
${axesSummary}

### Axes Faibles (prioritaires à explorer)
${weakAxes.length > 0 ? weakAxes.map(a => `- ${a.label} (${a.score}/100): ${a.justification}`).join("\n") : "Aucun axe critique"}

### Risques Identifiés
${risksStr || "Aucun risque identifié"}

## INSTRUCTIONS
En te basant sur ce contexte, aide l'utilisateur à explorer les incertitudes de son projet. Commence par identifier le point le plus critique à valider. Ne répète pas l'analyse -- challenge et fais avancer la réflexion.`;
}

function buildStructurationSystemPrompt(ctx: ChatRequest["projectContext"], lang: string): string {
  // Marcus persona -- structuration expert
  const axesSummary = ctx.axes
    .map(a => `- ${a.label}: ${a.score}/100 ${a.score >= 70 ? "[STRONG]" : ""}`)
    .join("\n");

  const strongAxes = ctx.axes.filter(a => a.score >= 70);
  const leversStr = ctx.levers
    ? ctx.levers.map(l => `- [${l.expected_impact}] ${l.action} (${l.axis})`).join("\n")
    : "Aucun levier spécifique";

  return `Tu es Marcus, expert en Structuration chez K3RN.LABS. Tu accompagnes les entrepreneurs dont les projets ont été validés (GO) et doivent maintenant être structurés en plan d'action.

## TON RÔLE
- Aider à structurer l'idée en business model viable
- Définir la proposition de valeur, le modèle de revenus, les KPIs
- Créer un plan d'action concret avec des jalons mesurables
- Identifier les ressources nécessaires et les prochaines étapes
- Tu es pragmatique et orienté résultats

## STYLE
- Stratégique et structuré
- Tu proposes des frameworks (Business Model Canvas, Lean Canvas, etc.)
- Tu donnes des recommandations actionnables
- Tu penses en termes de milestones et de métriques
- Réponds toujours dans la langue: ${lang === "fr" ? "français" : lang === "es" ? "español" : "English"}
- Sois structuré: utilise des listes et des sections quand c'est pertinent

## CONTEXTE DU PROJET
**${ctx.title}** (Score: ${ctx.globalScore}/100 — ${ctx.recommendation}, Confiance: ${ctx.confidenceLevel})

${ctx.description}

### Synthèse de l'Analyse
"${ctx.synthesis}"

### Détail des Axes
${axesSummary}

### Forces (axes à capitaliser)
${strongAxes.length > 0 ? strongAxes.map(a => `- ${a.label} (${a.score}/100): ${a.justification}`).join("\n") : "Aucune force dominante identifiée"}

### Leviers d'Action
${leversStr}

## INSTRUCTIONS
En te basant sur ce contexte, aide l'utilisateur à structurer son projet en plan d'action. Commence par proposer une structure de Business Model Canvas simplifié, puis aide à définir les prochaines étapes concrètes.`;
}

export async function POST(req: Request) {
  try {
    const body: ChatRequest = await req.json();
    const { messages, projectContext, labType, language } = body;

    // Validation
    if (!messages || !Array.isArray(messages) || messages.length === 0) {
      return Response.json(
        { error: { code: "INVALID_INPUT", message: "Messages array required" } },
        { status: 400 }
      );
    }

    if (!projectContext || !labType) {
      return Response.json(
        { error: { code: "INVALID_INPUT", message: "projectContext and labType required" } },
        { status: 400 }
      );
    }

    // Build system prompt based on lab type
    const systemPrompt = labType === "discovery"
      ? buildDiscoverySystemPrompt(projectContext, language || "fr")
      : buildStructurationSystemPrompt(projectContext, language || "fr");

    // Stream response from Claude
    const stream = await anthropic.messages.stream({
      model: CHAT_MODEL,
      max_tokens: 1024,
      temperature: 0.7,
      system: systemPrompt,
      messages: messages.map(m => ({
        role: m.role,
        content: m.content,
      })),
    });

    // Return as a ReadableStream using the SDK's built-in streaming
    const encoder = new TextEncoder();
    const readableStream = new ReadableStream({
      async start(controller) {
        try {
          for await (const event of stream) {
            if (
              event.type === "content_block_delta" &&
              event.delta.type === "text_delta"
            ) {
              const chunk = `data: ${JSON.stringify({ text: event.delta.text })}\n\n`;
              controller.enqueue(encoder.encode(chunk));
            }
          }
          controller.enqueue(encoder.encode("data: [DONE]\n\n"));
          controller.close();
        } catch (error) {
          const err = error as Error;
          controller.enqueue(
            encoder.encode(`data: ${JSON.stringify({ error: err.message })}\n\n`)
          );
          controller.close();
        }
      },
    });

    return new Response(readableStream, {
      headers: {
        "Content-Type": "text/event-stream",
        "Cache-Control": "no-cache",
        Connection: "keep-alive",
      },
    });
  } catch (error) {
    const err = error as Error & { status?: number };
    if (err.status === 429) {
      return Response.json(
        { error: { code: "AI_RATE_LIMITED", message: "Rate limit exceeded" } },
        { status: 429 }
      );
    }
    console.error("Expert chat error:", err);
    return Response.json(
      { error: { code: "INTERNAL_ERROR", message: err.message } },
      { status: 500 }
    );
  }
}
```

**Key design decisions:**
- Uses `anthropic.messages.stream()` for SSE-based streaming. The SDK at `^0.74.0` supports this method.
- The system prompt is built dynamically from project data, giving the AI full context about the analysis.
- Two distinct personas (Ava/Marcus) with completely different instructions, tone, and focus areas.
- Uses `claude-sonnet-4-20250514` by default for chat (cost-effective for conversational use). Configurable via env var `EXPERT_CHAT_MODEL`.
- SSE format (`data: {...}\n\n`) is standard for streaming frontends.
- The language from the i18n store is passed through so the AI responds in the correct language.

