**Question generation logic (pure client-side, no AI needed):**
```typescript
function generateExplorationQuestions(project: StoredProject): ExplorationQuestion[] {
  const questions: ExplorationQuestion[] = [];
  const fullResult = project.fullResult;

  if (!fullResult) return questions;

  // From weak axes
  const AXIS_KEYS = ["problem","market","differentiation","feasibility","business","founder_fit"] as const;
  for (const axis of AXIS_KEYS) {
    const data = fullResult.analysis[axis];
    if (data.score < 60) {
      questions.push({
        id: `axis-${axis}`,
        source: "axis",
        axis,
        question: `Comment valider/renforcer l'axe "${axis}" ?`,
        context: data.justification,
        severity: data.score < 30 ? "HIGH" : data.score < 50 ? "MEDIUM" : "LOW",
      });
    }
  }

  // From risks
  for (const risk of fullResult.risks) {
    questions.push({
      id: `risk-${risk.axis}-${risk.severity}`,
      source: "risk",
      axis: risk.axis,
      question: `Comment mitiger ce risque ?`,
      context: risk.description,
      severity: risk.severity,
    });
  }

  return questions;
}
```

