2. **Send message flow**:
   ```typescript
   async function handleSendMessage() {
     if (!input.trim() || isStreaming || !project) return;

     const userMessage = { role: "user" as const, content: input };
     const newMessages = [...messages, userMessage];
     setMessages(newMessages);
     setInput("");
     setIsStreaming(true);

     // Build project context from StoredProject
     const projectContext = {
       title: project.title,
       description: project.description,
       globalScore: project.globalScore,
       recommendation: project.recommendation,
       confidenceLevel: project.confidenceLevel,
       axes: project.analysis.axes,
       synthesis: project.analysis.synthesis,
       risks: project.analysis.risks,
       levers: project.fullResult?.levers?.map(l => ({
         axis: l.axis,
         action: l.action,
         expected_impact: l.expected_impact,
       })),
     };

     try {
       const response = await fetch("/api/expert-chat", {
         method: "POST",
         headers: { "Content-Type": "application/json" },
         body: JSON.stringify({
           messages: newMessages,
           projectContext,
           labType,
           language: currentLang.toLowerCase(),
         }),
       });

       if (!response.ok) throw new Error("Chat request failed");

       // Stream SSE response
       const reader = response.body?.getReader();
       const decoder = new TextDecoder();
       let assistantContent = "";

       // Add empty assistant message
       setMessages(prev => [...prev, { role: "assistant", content: "" }]);

       while (reader) {
         const { done, value } = await reader.read();
         if (done) break;

         const text = decoder.decode(value);
         const lines = text.split("\n");

         for (const line of lines) {
           if (line.startsWith("data: ")) {
             const data = line.slice(6);
             if (data === "[DONE]") break;
             try {
               const parsed = JSON.parse(data);
               if (parsed.text) {
                 assistantContent += parsed.text;
                 setMessages(prev => {
                   const updated = [...prev];
                   updated[updated.length - 1] = {
                     role: "assistant",
                     content: assistantContent,
                   };
                   return updated;
                 });
               }
             } catch {}
           }
         }
       }
     } catch (err) {
       setError("Erreur de connexion");
       toast.error("Chat expert indisponible");
     } finally {
       setIsStreaming(false);
     }
   }
   ```

