  - Lab 2: Show only "M" (Marcus) avatar, highlighted
  - Default (no lab): Keep current display

---

#### STEP 9: `src/app/workspace/laboratoire-1-discovery/[id]/page.tsx` (MODIFIED)

**Purpose:** Wire up Lab 1 with real data and lab-specific components.

**Current state:** 31 lines, identical stub using DossierPanel + CanvasBoard + ExpertChat.

**New implementation:**

```typescript
"use client";

import { useParams } from "next/navigation";
import { useProject } from "@/hooks/use-project";
import { WorkspaceHeader } from "@/components/workspace/header";
import { DiscoveryPanel } from "@/components/workspace/lab1/discovery-panel";
import { DiscoveryWorkspace } from "@/components/workspace/lab1/discovery-workspace";
import { ExpertChat } from "@/components/workspace/expert-chat";

export default function Lab1DiscoveryPage() {
  const params = useParams();
  const id = params.id as string;
  const { project, isLoading } = useProject(id);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-screen bg-[#22242B] text-white">
        <div className="flex flex-col items-center gap-4">
          <div className="w-8 h-8 border-2 border-[#F75105] border-t-transparent rounded-full animate-spin" />
          <span className="text-sm text-gray-400">Chargement du dossier...</span>
        </div>
      </div>
    );
  }

  if (!project) {
    return (
      <div className="flex items-center justify-center h-screen bg-[#22242B] text-white">
        <div className="text-center">
          <h2 className="text-xl font-medium mb-2">Dossier introuvable</h2>
          <p className="text-gray-400 text-sm">ID: {id}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-[#22242B] text-white font-sans overflow-hidden">
      <WorkspaceHeader
        projectId={id}
        project={project}
        labName="Discovery"
        labNumber={1}
      />
      <div className="flex-1 flex overflow-hidden">
        <DiscoveryPanel project={project} />
        <DiscoveryWorkspace project={project} />
        <ExpertChat
          projectId={id}
          project={project}
          labType="discovery"
        />
      </div>
    </div>
  );
}
```

