/**
 * K3RN.LABS — POST /api/analysis
 * Analyse canonique d'une idée via Claude API
 *
 * Pipeline :
 * 1. Validation input (JSON Schema)
 * 2. Assemblage prompt (system + orchestrator + experts + constraints)
 * 3. Appel Claude API
 * 4. Parsing réponse JSON
 * 5. Validation output LLM (JSON Schema)
 * 6. Calcul score global (formule canonique serveur)
 * 7. Détermination décision (logique serveur)
 * 8. Détection enrichissement
 * 9. Retour réponse conforme
 */

import { NextResponse } from 'next/server';
import Anthropic from '@anthropic-ai/sdk';
import { validateAnalysisInput, validateLlmRawOutput } from '@/lib/analysis/validators';
import { calculateGlobalScore } from '@/lib/analysis/scoring';
import { determineDecision } from '@/lib/analysis/decision';
import { computeEnrichmentDecision } from '@/lib/analysis/enrichment';
import { CANONICAL_WEIGHTS, SCHEMA_VERSION } from '@/lib/analysis/constants';
import { assembleSystemPrompt, buildUserMessage, CURRENT_VERSION } from '@/lib/analysis/prompts/registry';
import type { AnalysisOutput, AnalysisAxes, ApiError } from '@/lib/analysis/types';

// ─── Claude API client ──────────────────────────────────────────
const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});
